78:/**
79: * Build the upstream yields map for a rig: all completed engine yields
80: * keyed by engine id. Passed as context.upstream to the engine's run().
81: */
82:function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
83:  const upstream: Record<string, unknown> = {};
84:  for (const engine of rig.engines) {
85:    if (engine.status === 'completed' && engine.yields !== undefined) {
86:      upstream[engine.id] = engine.yields;
87:    }
88:  }
89:  return upstream;
90:}
92:/**
93: * Find the first pending engine whose entire upstream is completed.
94: * Returns null if no runnable engine exists.
95: */
96:function findRunnableEngine(rig: RigDoc): EngineInstance | null {
97:  for (const engine of rig.engines) {
98:    if (engine.status !== 'pending') continue;
99:    const allUpstreamDone = engine.upstream.every((upstreamId) => {
100:      const dep = rig.engines.find((e) => e.id === upstreamId);
101:      return dep?.status === 'completed';
102:    });
103:    if (allUpstreamDone) return engine;
104:  }
105:  return null;
106:}
108:/**
109: * Determine whether a rig should enter the blocked state.
110: *
111: * A rig is blocked when:
112: * - No engine is currently running
113: * - No engine is runnable (pending with all upstream completed)
114: * - At least one engine is blocked
115: */
116:function isRigBlocked(engines: EngineInstance[]): boolean {
117:  const hasRunning = engines.some((e) => e.status === 'running');
118:  if (hasRunning) return false;
119:  const hasBlocked = engines.some((e) => e.status === 'blocked');
120:  if (!hasBlocked) return false;
121:  // Check runnability by constructing a minimal RigDoc-like object
122:  const syntheticRig = { engines } as RigDoc;
123:  return findRunnableEngine(syntheticRig) === null;
124:}
126:/**
127: * Produce the five-engine static pipeline for a writ.
128: * Each engine receives only the givens it needs.
129: * Upstream yields arrive via context.upstream at run time.
130: */
131:function buildStaticEngines(writ: WritDoc, config: SpiderConfig): EngineInstance[] {
132:  const role = config.role ?? 'artificer';
133:  const reviewGivens: Record<string, unknown> = {
134:    writ,
135:    role: 'reviewer',
136:    ...(config.buildCommand !== undefined ? { buildCommand: config.buildCommand } : {}),
137:    ...(config.testCommand !== undefined ? { testCommand: config.testCommand } : {}),
138:  };
140:  return [
141:    { id: 'draft',     designId: 'draft',     status: 'pending', upstream: [],           givensSpec: { writ } },
142:    { id: 'implement', designId: 'implement', status: 'pending', upstream: ['draft'],     givensSpec: { writ, role } },
143:    { id: 'review',    designId: 'review',    status: 'pending', upstream: ['implement'], givensSpec: reviewGivens },
144:    { id: 'revise',    designId: 'revise',    status: 'pending', upstream: ['review'],    givensSpec: { writ, role } },
145:    { id: 'seal',      designId: 'seal',      status: 'pending', upstream: ['revise'],    givensSpec: {} },
146:  ];
147:}
149:// ── Template-based rig building ────────────────────────────────────────
151:/**
152: * Look up the rig template for a given writ type.
153: * Falls back to 'default' template if no exact match.
154: * Throws if no matching template is found.
155: */
156:function lookupTemplate(writType: string, config: SpiderConfig): RigTemplate {
157:  const templates = config.rigTemplates;
158:  if (templates) {
159:    if (writType in templates) return templates[writType];
160:    if ('default' in templates) return templates['default'];
161:  }
162:  throw new Error(
163:    `[spider] No rig template found for writ type "${writType}" and no "default" template configured.`
164:  );
165:}
167:/**
168: * Resolve a template engine's givens map using a variables context.
169: * '$writ' → WritDoc, '$role' → role string, '$spider.<key>' → spiderConfig[key].
170: * Keys resolving to undefined are omitted from the output.
171: * Non-'$' prefixed values are passed through as literals.
172: */
173:function resolveGivens(
174:  givens: Record<string, unknown> | undefined,
175:  context: { writ: WritDoc; role: string; spiderConfig: SpiderConfig },
176:): Record<string, unknown> {
177:  const result: Record<string, unknown> = {};
178:  for (const [key, value] of Object.entries(givens ?? {})) {
179:    if (typeof value !== 'string' || !value.startsWith('$')) {
180:      result[key] = value;
181:    } else if (value === '$writ') {
182:      result[key] = context.writ;
183:    } else if (value === '$role') {
184:      result[key] = context.role;
185:    } else if (/^\$spider\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(value)) {
186:      const spiderKey = value.slice('$spider.'.length);
187:      const resolved = (context.spiderConfig as Record<string, unknown>)[spiderKey];
188:      if (resolved !== undefined) {
189:        result[key] = resolved;
190:      }
191:      // undefined → omit key entirely
192:    }
193:    // Unrecognized $-prefixed strings are caught at validation time
194:  }
195:  return result;
196:}
198:/**
199: * Build EngineInstance array and resolutionEngineId from a RigTemplate.
200: */
201:function buildFromTemplate(
202:  template: RigTemplate,
203:  context: { writ: WritDoc; role: string; spiderConfig: SpiderConfig },
204:): { engines: EngineInstance[]; resolutionEngineId?: string } {
205:  const engines: EngineInstance[] = template.engines.map((entry) => ({
206:    id: entry.id,
207:    designId: entry.designId,
208:    status: 'pending' as const,
209:    upstream: entry.upstream ?? [],
210:    givensSpec: resolveGivens(entry.givens, context),
211:  }));
212:  return { engines, resolutionEngineId: template.resolutionEngine };
213:}
