219:function validateTemplates(
220:  rigTemplates: Record<string, RigTemplate>,
221:  fabricator: FabricatorApi,
222:): void {
223:  const builtinEngineIds = new Set([
224:    draftEngine.id,
225:    implementEngine.id,
226:    reviewEngine.id,
227:    reviseEngine.id,
228:    sealEngine.id,
229:  ]);
231:  for (const [templateKey, template] of Object.entries(rigTemplates)) {
232:    const engines = template.engines;
234:    // R13: Non-empty check
235:    if (engines.length === 0) {
236:      throw new Error(`[spider] rigTemplates.${templateKey}: template has no engines`);
237:    }
239:    // R6b: Duplicate ID check
240:    const engineIds = new Set<string>();
241:    for (const engine of engines) {
242:      if (engineIds.has(engine.id)) {
243:        throw new Error(
244:          `[spider] rigTemplates.${templateKey}: duplicate engine id "${engine.id}"`
245:        );
246:      }
247:      engineIds.add(engine.id);
248:    }
250:    // R6a: designId check
251:    for (const engine of engines) {
252:      const knownInFabricator = fabricator.getEngineDesign(engine.designId) !== undefined;
253:      const knownBuiltin = builtinEngineIds.has(engine.designId);
254:      if (!knownInFabricator && !knownBuiltin) {
255:        throw new Error(
256:          `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown designId "${engine.designId}"`
257:        );
258:      }
259:    }
261:    // R6c: Upstream reference check
262:    for (const engine of engines) {
263:      for (const upstreamId of engine.upstream ?? []) {
264:        if (!engineIds.has(upstreamId)) {
265:          throw new Error(
266:            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown upstream "${upstreamId}"`
267:          );
268:        }
269:      }
270:    }
272:    // R6d: Cycle detection (DFS)
273:    {
274:      const visiting = new Set<string>();
275:      const visited = new Set<string>();
277:      const visit = (id: string): void => {
278:        if (visited.has(id)) return;
279:        if (visiting.has(id)) {
280:          throw new Error(
281:            `[spider] rigTemplates.${templateKey}: dependency cycle detected involving engine "${id}"`
282:          );
283:        }
284:        visiting.add(id);
285:        const engine = engines.find((e) => e.id === id)!;
286:        for (const dep of engine.upstream ?? []) {
287:          visit(dep);
288:        }
289:        visiting.delete(id);
290:        visited.add(id);
291:      };
293:      for (const engine of engines) {
294:        visit(engine.id);
295:      }
296:    }
298:    // R6e: resolutionEngine check
299:    if (template.resolutionEngine !== undefined && !engineIds.has(template.resolutionEngine)) {
300:      throw new Error(
301:        `[spider] rigTemplates.${templateKey}: resolutionEngine "${template.resolutionEngine}" is not an engine id in this template`
302:      );
303:    }
305:    // R7: Variable reference validation
306:    for (const engine of engines) {
307:      for (const value of Object.values(engine.givens ?? {})) {
308:        if (typeof value === 'string' && value.startsWith('$')) {
309:          if (
310:            value === '$writ' ||
311:            value === '$role' ||
312:            /^\$spider\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(value)
313:          ) {
314:            continue; // valid
315:          }
316:          throw new Error(
317:            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" has unrecognized variable "${value}"`
318:          );
319:        }
320:      }
321:    }
322:  }
323:}
