338:class BlockTypeRegistry {
339:  private readonly types = new Map<string, BlockType>();
341:  register(plugin: LoadedPlugin): void {
342:    if (isLoadedKit(plugin)) {
343:      this.registerFromKit(plugin.kit);
344:    } else if (isLoadedApparatus(plugin)) {
345:      if (plugin.apparatus.supportKit) {
346:        this.registerFromKit(plugin.apparatus.supportKit);
347:      }
348:    }
349:  }
351:  private registerFromKit(kit: Record<string, unknown>): void {
352:    const raw = kit.blockTypes;
353:    if (typeof raw !== 'object' || raw === null) return;
354:    for (const value of Object.values(raw as Record<string, unknown>)) {
355:      if (isBlockType(value)) {
356:        this.types.set(value.id, value);
357:      }
358:    }
359:  }
361:  get(id: string): BlockType | undefined {
362:    return this.types.get(id);
363:  }
364:}
