368:export function createSpider(): Plugin {
369:  let rigsBook: Book<RigDoc>;
370:  let sessionsBook: ReadOnlyBook<SessionDoc>;
371:  let writsBook: ReadOnlyBook<WritDoc>;
372:  let clerk: ClerkApi;
373:  let fabricator: FabricatorApi;
374:  let spiderConfig: SpiderConfig = {};
376:  const blockTypeRegistry = new BlockTypeRegistry();
378:  /**
379:   * In-memory store for block records that have been cleared.
380:   * Key: "rigId:engineId". Written when an engine is unblocked (via checker or resume()).
381:   * Read and deleted in tryRun() when building EngineRunContext.
382:   */
383:  const pendingPriorBlocks = new Map<string, BlockRecord>();
385:  // ── Internal crawl operations ─────────────────────────────────────
387:  /**
388:   * Mark an engine failed and propagate failure to the rig (same update).
389:   * Cancels all pending and blocked engines.
390:   */
391:  async function failEngine(
392:    rig: RigDoc,
393:    engineId: string,
394:    errorMessage: string,
395:  ): Promise<void> {
396:    const now = new Date().toISOString();
397:    const updatedEngines = rig.engines.map((e) => {
398:      if (e.id === engineId) {
399:        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
400:      }
401:      if (e.status === 'pending' || e.status === 'blocked') {
402:        return { ...e, status: 'cancelled' as const, block: undefined };
403:      }
404:      return e;
405:    });
406:    await rigsBook.patch(rig.id, {
407:      engines: updatedEngines,
408:      status: 'failed',
409:    });
410:  }
412:  /**
413:   * Phase 1 — collect.
414:   *
415:   * Find the first running engine with a sessionId whose session has
416:   * reached a terminal state. Populate yields and advance the engine
417:   * (and possibly the rig) to completed or failed.
418:   *
419:   * After collecting a completed engine, check whether the rig has
420:   * become blocked (no running engines, no runnable engines, some blocked).
421:   */
422:  async function tryCollect(): Promise<CrawlResult | null> {
423:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
424:    for (const rig of runningRigs) {
425:      for (const engine of rig.engines) {
426:        if (engine.status !== 'running' || !engine.sessionId) continue;
428:        const session = await sessionsBook.get(engine.sessionId);
429:        if (!session || session.status === 'running') continue;
431:        // Terminal session found — collect.
432:        const now = new Date().toISOString();
434:        if (session.status === 'failed' || session.status === 'timeout') {
435:          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
436:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
437:        }
439:        // Completed session — assemble yields via engine's collect() or generic default.
440:        const design = fabricator.getEngineDesign(engine.designId);
441:        let yields: unknown;
442:        if (design?.collect) {
443:          const givens = { ...engine.givensSpec };
444:          const upstream = buildUpstreamMap(rig);
445:          const context = { engineId: engine.id, upstream };
446:          yields = await design.collect(engine.sessionId!, givens, context);
447:        } else {
448:          yields = {
449:            sessionId: session.id,
450:            sessionStatus: session.status,
451:            ...(session.output !== undefined ? { output: session.output } : {}),
452:          };
453:        }
455:        if (!isJsonSerializable(yields)) {
456:          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
457:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
458:        }
460:        const updatedEngines = rig.engines.map((e) =>
461:          e.id === engine.id
462:            ? { ...e, status: 'completed' as const, yields, completedAt: now }
463:            : e,
464:        );
466:        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
468:        if (allCompleted) {
469:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'completed' });
470:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
471:        }
473:        // Check whether completing this engine has caused the rig to become blocked
474:        if (isRigBlocked(updatedEngines)) {
475:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'blocked' });
476:          return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
477:        }
479:        await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
480:        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
481:      }
482:    }
483:    return null;
484:  }
486:  /**
487:   * Phase 2 — checkBlocked.
488:   *
489:   * Query rigs with status 'running' or 'blocked'. For each blocked engine,
490:   * run the registered checker (respecting pollIntervalMs). If cleared,
491:   * transition the engine back to pending and restore the rig to running.
492:   * If not cleared, update lastCheckedAt and continue to the next engine.
493:   */
494:  async function tryCheckBlocked(): Promise<CrawlResult | null> {
495:    // Fetch both running rigs (may have blocked engines) and blocked rigs
496:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
497:    const blockedRigs = await rigsBook.find({ where: [['status', '=', 'blocked']] });
498:    const rigs = [...runningRigs, ...blockedRigs];
500:    for (const rig of rigs) {
501:      for (const engine of rig.engines) {
502:        if (engine.status !== 'blocked' || !engine.block) continue;
504:        const blockType = blockTypeRegistry.get(engine.block.type);
505:        if (!blockType) continue; // Type was unregistered after block was created; skip
507:        // Poll interval throttle
508:        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
509:          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
510:          if (elapsed < blockType.pollIntervalMs) continue;
511:        }
513:        let cleared: boolean;
514:        try {
515:          cleared = await blockType.check(engine.block.condition);
516:        } catch (err) {
517:          // Log warning, skip — engine stays blocked, retry next cycle
518:          console.warn(
519:            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
520:            err,
521:          );
522:          continue;
523:        }
525:        if (!cleared) {
526:          // Update lastCheckedAt and continue checking other engines
527:          const now = new Date().toISOString();
528:          const updatedEngines = rig.engines.map((e) =>
529:            e.id === engine.id
530:              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
531:              : e,
532:          );
533:          await rigsBook.patch(rig.id, { engines: updatedEngines });
534:          continue; // Check next engine
535:        }
537:        // Cleared — store block record in memory for priorBlock, then transition engine to pending
538:        const priorBlockRecord = engine.block;
