53:function buildCtx(): {
54:  ctx: StartupContext;
55:  fire: (event: string, ...args: unknown[]) => Promise<void>;
56:} {
57:  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
58:  const ctx: StartupContext = {
59:    on(event, handler) {
60:      const list = handlers.get(event) ?? [];
