50:/**
51: * Build a minimal StartupContext that captures and fires events.
52: */
53:function buildCtx(): {
54:  ctx: StartupContext;
55:  fire: (event: string, ...args: unknown[]) => Promise<void>;
56:} {
57:  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
58:  const ctx: StartupContext = {
59:    on(event, handler) {
60:      const list = handlers.get(event) ?? [];
61:      list.push(handler);
62:      handlers.set(event, list);
63:    },
64:  };
65:  async function fire(event: string, ...args: unknown[]): Promise<void> {
66:    for (const h of handlers.get(event) ?? []) {
67:      await h(...args);
68:    }
69:  }
70:  return { ctx, fire };
71:}
